package org.eclipse.rdf4j.sail.lmdb;

import static org.assertj.core.api.Assertions.assertThat;

import java.io.File;
import java.util.List;
import java.util.stream.Collectors;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.query.BindingSet;
import org.eclipse.rdf4j.query.QueryResults;
import org.eclipse.rdf4j.repository.sail.SailRepository;
import org.eclipse.rdf4j.repository.sail.SailRepositoryConnection;
import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

/**
 * Differential tests for native property-path evaluation (BFS over value ids): every query runs once natively and once
 * with {@code rdf4j.lmdb.nativeQueryEngine.enabled=false} (the generic PathIteration), and the result multisets must
 * match. The graph has a chain, a diamond (two routes to one node — set semantics must not duplicate), a cycle, a
 * self-loop, a literal leaf, a disconnected edge with another predicate, and one edge in a named graph.
 */
public class LmdbNativePropertyPathTest {

	private static final String EX = "http://example.com/";
	private static final String NATIVE_FLAG = "rdf4j.lmdb.nativeQueryEngine.enabled";

	@TempDir
	File dataDir;

	private SailRepository repository;

	@BeforeEach
	public void setUp() {
		repository = new SailRepository(new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc,ospc")));
		try (SailRepositoryConnection conn = repository.getConnection()) {
			ValueFactory vf = conn.getValueFactory();
			IRI p = vf.createIRI(EX, "p");
			IRI q = vf.createIRI(EX, "q");
			IRI a = vf.createIRI(EX, "a");
			IRI b = vf.createIRI(EX, "b");
			IRI c = vf.createIRI(EX, "c");
			IRI d = vf.createIRI(EX, "d");
			IRI e = vf.createIRI(EX, "e");
			IRI f = vf.createIRI(EX, "f");
			// chain a -> b -> c -> d
			conn.add(a, p, b);
			conn.add(b, p, c);
			conn.add(c, p, d);
			// diamond: a -> e and b -> e (two routes from a to e)
			conn.add(a, p, e);
			conn.add(b, p, e);
			// cycle e -> a (a reaches itself)
			conn.add(e, p, a);
			// self loop f -> f
			conn.add(f, p, f);
			// literal leaf
			conn.add(d, p, vf.createLiteral("leaf"));
			// another predicate for sequences/alternations and a q-only node
			conn.add(a, q, c);
			conn.add(c, q, f);
			// one p edge in a named graph (default dataset still sees it)
			conn.add(e, p, vf.createIRI(EX, "inGraph"), vf.createIRI(EX, "g1"));
		}
	}

	@AfterEach
	public void tearDown() {
		repository.shutDown();
	}

	private List<String> rows(String query) {
		try (SailRepositoryConnection conn = repository.getConnection()) {
			List<BindingSet> result = QueryResults.asList(conn.prepareTupleQuery(query).evaluate());
			return result.stream()
					.map(bs -> bs.getBindingNames()
							.stream()
							.sorted()
							.map(name -> name + "=" + bs.getValue(name))
							.collect(Collectors.joining(";", "[", "]")))
					.sorted()
					.collect(Collectors.toList());
		}
	}

	private List<String> genericRows(String query) {
		String previous = System.getProperty(NATIVE_FLAG);
		try {
			System.setProperty(NATIVE_FLAG, "false");
			return rows(query);
		} finally {
			if (previous == null) {
				System.clearProperty(NATIVE_FLAG);
			} else {
				System.setProperty(NATIVE_FLAG, previous);
			}
		}
	}

	private void assertSameAsGeneric(String query) {
		assertThat(rows(query)).as("native vs generic for:\n" + query).isEqualTo(genericRows(query));
	}

	private static String q(String body) {
		return "PREFIX ex: <" + EX + ">\n" + body;
	}

	@Test
	public void plusFromBoundSubject() {
		assertSameAsGeneric(q("SELECT ?o WHERE { ex:a ex:p+ ?o . }"));
	}

	@Test
	public void starFromBoundSubject() {
		assertSameAsGeneric(q("SELECT ?o WHERE { ex:a ex:p* ?o . }"));
	}

	@Test
	public void plusToBoundObject() {
		assertSameAsGeneric(q("SELECT ?s WHERE { ?s ex:p+ ex:e . }"));
	}

	@Test
	public void starToBoundObject() {
		assertSameAsGeneric(q("SELECT ?s WHERE { ?s ex:p* ex:d . }"));
	}

	@Test
	public void plusBothBoundReachable() {
		assertSameAsGeneric(q("SELECT (COUNT(*) AS ?c) WHERE { ex:a ex:p+ ex:d . }"));
	}

	@Test
	public void plusBothBoundCycleToSelf() {
		// a -> ... -> e -> a: (a,a) is reachable through the cycle
		assertSameAsGeneric(q("SELECT (COUNT(*) AS ?c) WHERE { ex:a ex:p+ ex:a . }"));
	}

	@Test
	public void plusBothBoundUnreachable() {
		assertSameAsGeneric(q("SELECT (COUNT(*) AS ?c) WHERE { ex:d ex:p+ ex:a . }"));
	}

	@Test
	public void starBothBoundIdentity() {
		// zero-length: x relates to itself regardless of edges
		assertSameAsGeneric(q("SELECT (COUNT(*) AS ?c) WHERE { ex:d ex:p* ex:d . }"));
	}

	@Test
	public void plusBothFree() {
		assertSameAsGeneric(q("SELECT ?s ?o WHERE { ?s ex:p+ ?o . }"));
	}

	@Test
	public void starBothFree() {
		// zero-length identity ranges over every vertex in the dataset
		assertSameAsGeneric(q("SELECT ?s ?o WHERE { ?s ex:p* ?o . }"));
	}

	@Test
	public void selfLoopPlus() {
		assertSameAsGeneric(q("SELECT ?o WHERE { ex:f ex:p+ ?o . }"));
	}

	@Test
	public void inversePathPlus() {
		assertSameAsGeneric(q("SELECT ?o WHERE { ex:e ^ex:p+ ?o . }"));
	}

	@Test
	public void pathJoinedWithPatternOnPrefix() {
		// ?s comes from an ordinary pattern; the path runs correlated per binding
		assertSameAsGeneric(q("SELECT ?s ?o WHERE { ?s ex:q ?m . ?s ex:p+ ?o . }"));
	}

	@Test
	public void pathFeedingPattern() {
		assertSameAsGeneric(q("SELECT ?o ?n WHERE { ex:a ex:p+ ?o . ?o ex:q ?n . }"));
	}

	@Test
	public void pathUnderCount() {
		assertSameAsGeneric(q("SELECT (COUNT(?o) AS ?c) (COUNT(DISTINCT ?o) AS ?d) WHERE { ex:a ex:p+ ?o . }"));
	}

	@Test
	public void distinctReachabilityAcrossSubjects() {
		assertSameAsGeneric(q("SELECT DISTINCT ?o WHERE { ?s ex:p+ ?o . }"));
	}

	@Test
	public void sequencePathFallsBack() {
		assertSameAsGeneric(q("SELECT ?o WHERE { ex:a (ex:p/ex:q)+ ?o . }"));
	}

	@Test
	public void alternationPathFallsBack() {
		assertSameAsGeneric(q("SELECT ?o WHERE { ex:a (ex:p|ex:q)+ ?o . }"));
	}

	@Test
	public void graphScopedPathFallsBack() {
		assertSameAsGeneric(q("SELECT ?g ?o WHERE { GRAPH ?g { ex:e ex:p+ ?o . } }"));
	}

	@Test
	public void sameVariableBothEndsFallsBack() {
		assertSameAsGeneric(q("SELECT ?x WHERE { ?x ex:p+ ?x . }"));
	}

	@Test
	public void zeroOrOnePath() {
		assertSameAsGeneric(q("SELECT ?o WHERE { ex:a ex:p? ?o . }"));
	}

	@Test
	public void nativePathActuallyEngages() {
		long before = PathPlan.ENGAGED.get();
		rows(q("SELECT ?o WHERE { ex:a ex:p+ ?o . }"));
		assertThat(PathPlan.ENGAGED.get())
				.as("the native BFS should evaluate the bound-subject one-predicate path")
				.isGreaterThan(before);
	}

	@Test
	public void gatedShapesDoNotEngage() {
		long before = PathPlan.ENGAGED.get();
		rows(q("SELECT ?o WHERE { ex:a (ex:p/ex:q)+ ?o . }"));
		rows(q("SELECT ?g ?o WHERE { GRAPH ?g { ex:e ex:p+ ?o . } }"));
		assertThat(PathPlan.ENGAGED.get())
				.as("sequence paths and graph-variable scoping must fall back")
				.isEqualTo(before);
	}
}
